import{_ as e,c as t,o,a as i}from"./app.f45dc67e.js";const g=JSON.parse('{"title":"Change Log","description":"","frontmatter":{},"headers":[{"level":2,"title":"v6.2.6 (Latest)","slug":"v6-2-6-latest"},{"level":2,"title":"v6.0.2","slug":"v6-0-2"},{"level":2,"title":"v5.6.2","slug":"v5-6-2"},{"level":2,"title":"v5.1.1","slug":"v5-1-1"},{"level":2,"title":"v4.3.0","slug":"v4-3-0"},{"level":2,"title":"v3.1.0","slug":"v3-1-0"},{"level":2,"title":"v2.3.4","slug":"v2-3-4"},{"level":2,"title":"v2.3.3","slug":"v2-3-3"},{"level":2,"title":"v2.3.2","slug":"v2-3-2"},{"level":2,"title":"v2.3.1","slug":"v2-3-1"},{"level":2,"title":"v2.3.0","slug":"v2-3-0"},{"level":2,"title":"v2.2.0","slug":"v2-2-0"},{"level":2,"title":"v2.1.0","slug":"v2-1-0"},{"level":2,"title":"v2.0.0","slug":"v2-0-0"}],"relativePath":"changeLog/index.md"}'),l={name:"changeLog/index.md"},d=i('<h1 id="change-log" tabindex="-1">Change Log <a class="header-anchor" href="#change-log" aria-hidden="true">#</a></h1><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Although the version number uses the version number of Strve, the content includes not only the updated content of Strve, but also the updated content of other official tools in the same period.</p></div><h2 id="v6-2-6-latest" tabindex="-1">v6.2.6 (Latest) <a class="header-anchor" href="#v6-2-6-latest" aria-hidden="true">#</a></h2><ul><li>Optimize the Diff algorithm using the longest increasing subsequence;</li><li>Added the usage of named components and introduced the <strong>&quot;isolated island&quot;</strong> feature;</li><li>Event processing cancels the <code>@</code> abbreviation;</li><li>Change API <code>setData</code>, <code>domInfo</code>;</li><li>Delete API <code>defineCustomElement</code>, <code>propsData</code>;</li><li>Delete the built-in properties <code>$props</code> and <code>$name</code>;</li><li>Added built-in attributes <code>$render</code> and <code>$id</code>;</li><li>Added APIs <code>createStateFlow</code> and <code>registerComponent</code>;</li><li>Publish <a href="https://www.npmjs.com/package/strve-reactivity" target="_blank" rel="noopener noreferrer">strve-reactivity</a>\uFF1B</li><li>Update <a href="https://www.npmjs.com/package/babel-plugin-strve" target="_blank" rel="noopener noreferrer">babel-plugin-strve</a>;</li><li>Update <a href="https://www.npmjs.com/package/babel-plugin-jsx-to-strve" target="_blank" rel="noopener noreferrer">babel-plugin-jsx-to-strve</a>;</li><li>Update <a href="https://www.npmjs.com/package/strve-router" target="_blank" rel="noopener noreferrer">strve-router</a>;</li><li>Update <a href="https://www.npmjs.com/package/create-strve-app" target="_blank" rel="noopener noreferrer">create-strve-app</a>;</li></ul><h2 id="v6-0-2" tabindex="-1">v6.0.2 <a class="header-anchor" href="#v6-0-2" aria-hidden="true">#</a></h2><ul><li>Remove <code>useFirstKey</code>;</li><li>Added <code>key</code> attribute. This special attribute <code>key</code> is mainly used as a hint for Vue&#39;s virtual DOM algorithm and is used to identify vnode when comparing the old and new node lists. The double-ended Diff algorithm is used internally, which is more efficient;</li><li>Remove static tag <code>$key</code>;</li><li>Added built-in attribute <code>$ref</code>;</li><li>Change API <code>h</code> to <code>html</code>;</li><li>There must be one and only one root node, use the <code>&lt;fragment&gt;&lt;/fragment&gt;</code> tag;</li><li>Update <a href="https://www.npmjs.com/package/babel-plugin-strve" target="_blank" rel="noopener noreferrer">babel-plugin-strve</a>;</li><li>Update <a href="https://www.npmjs.com/package/babel-plugin-jsx-to-strve" target="_blank" rel="noopener noreferrer">babel-plugin-jsx-to-strve</a>;</li><li>Update <a href="https://www.npmjs.com/package/strve-router" target="_blank" rel="noopener noreferrer">strve-router</a>;</li><li>Update <a href="https://www.npmjs.com/package/create-strve-app" target="_blank" rel="noopener noreferrer">create-strve-app</a>;</li></ul><h2 id="v5-6-2" tabindex="-1">v5.6.2 <a class="header-anchor" href="#v5-6-2" aria-hidden="true">#</a></h2><ul><li>Optimize <code>onMounted</code>, <code>nextTick</code> API;</li><li>Support JSX syntax;</li><li>Update <a href="https://www.npmjs.com/package/babel-plugin-strve" target="_blank" rel="noopener noreferrer">babel-plugin-strve</a>, add call expression mode;</li><li>Release <a href="https://www.npmjs.com/package/babel-plugin-jsx-to-strve" target="_blank" rel="noopener noreferrer">babel-plugin-jsx-to-strve</a>, which converts JSX to markup templates for use with Strve.js ;</li></ul><h2 id="v5-1-1" tabindex="-1">v5.1.1 <a class="header-anchor" href="#v5-1-1" aria-hidden="true">#</a></h2><ul><li>Add the compile module;</li><li>Adjust the source code warehouse building module;</li><li>Different versions: <ol><li>Full version: both the compiler (code used to compile template strings into JavaScript rendering functions) and the runtime version are included;</li><li>Runtime: code used to create instances, render and process virtual DOM. Basically, it is to remove everything else from the compiler;</li></ol></li><li>The prefix of listening events can be abbreviated as @;</li><li>Introducing compilers: Develop a babel plugin <a href="https://www.npmjs.com/package/babel-plugin-strve" target="_blank" rel="noopener noreferrer">(babel-plugin-strve)</a> to render the HTML template string into a Virtual Dom, which is transferred from the previous runtime to the compilation time;</li><li>Introducing Web Components: <ol><li>New defineCustomElement API supports the introduction of Web Components;</li><li>Support for Web Components UI frameworks (e.g. <a href="https://quark-design.hellobike.com/" target="_blank" rel="noopener noreferrer">https://quark-design.hellobike.com/</a>);</li><li>Add the customElement field in the setDataAPI to update the component view as needed;</li></ol></li></ul><h2 id="v4-3-0" tabindex="-1">v4.3.0 <a class="header-anchor" href="#v4-3-0" aria-hidden="true">#</a></h2><ul><li>Add <code>propsData</code>\u3001<code>onMounted</code>\u3001<code>onUnmounted</code>\u3001<code>nextTick</code>\u3001<code>domInfo</code>API;</li><li>remove <code>emit</code>\u3001<code>watchDom</code>\u3001<code>clone</code>API;</li><li>Added <code>$props</code> tag;</li><li>Added iife file format, an automatic function, suitable as <code>&lt;script&gt;</code> tag;</li></ul><h2 id="v3-1-0" tabindex="-1">v3.1.0 <a class="header-anchor" href="#v3-1-0" aria-hidden="true">#</a></h2><ul><li><p>Modify API:</p><table><thead><tr><th>Old API</th><th>New API</th></tr></thead><tbody><tr><td><code>Strve</code></td><td><code>createApp</code></td></tr><tr><td><code>render</code></td><td><code>h</code></td></tr><tr><td><code>updateView</code></td><td><code>setData</code></td></tr><tr><td><code>watchDOMChange</code></td><td><code>watchDom</code></td></tr><tr><td><code>emitEvent</code></td><td><code>emit</code></td></tr><tr><td><code>strveVersion</code></td><td><code>version</code></td></tr><tr><td><code>deepCloneData</code></td><td><code>clone</code></td></tr></tbody></table></li><li><p>Adjust <code>createApp</code> API;</p></li><li><p><code>useFkey</code> tag changed to <code>useFirstKey</code>;</p></li><li><p>add tags <code>$key</code>, <code>$name</code>;</p></li><li><p>Add component tag <code>&lt;component&gt;</code>, empty node tag <code>&lt;null&gt;</code>;</p></li><li><p>Adjust <code>setData</code> API;</p></li><li><p>Optimize the Diff algorithm;</p></li><li><p>TypeScript refactoring code;</p></li></ul><h2 id="v2-3-4" tabindex="-1">v2.3.4 <a class="header-anchor" href="#v2-3-4" aria-hidden="true">#</a></h2><ul><li>Added data deep copy API <code>deepCloneData</code>;</li></ul><h2 id="v2-3-3" tabindex="-1">v2.3.3 <a class="header-anchor" href="#v2-3-3" aria-hidden="true">#</a></h2><ul><li>Parameter adjustment of <code>Strve</code> API;</li></ul><h2 id="v2-3-2" tabindex="-1">v2.3.2 <a class="header-anchor" href="#v2-3-2" aria-hidden="true">#</a></h2><ul><li>HTML tag content supports displaying non-string types;</li><li>The <code>${}</code> symbol is used for data binding, and the <code>{}</code> symbol is no longer supported;</li><li>View templates support multiple root nodes;</li><li>View template supports Text node;</li><li>Fixed switching states during conditional rendering, and nodes could not be rendered correctly;</li><li>Added <code>watchDOMChange</code> API for monitoring DOM tree changes;</li><li>Added support for HTML template string highlighting (VSCode editor needs to install <code>es6-string-html</code> plugin);</li><li>Remove the <code>data</code> attribute parameter of the <code>Strve</code> API;</li><li>View templates support Class writing;</li></ul><h2 id="v2-3-1" tabindex="-1">v2.3.1 <a class="header-anchor" href="#v2-3-1" aria-hidden="true">#</a></h2><ul><li>Modify some error messages;</li></ul><h2 id="v2-3-0" tabindex="-1">v2.3.0 <a class="header-anchor" href="#v2-3-0" aria-hidden="true">#</a></h2><ul><li>Added version number <code>strveVersion</code> API;</li><li>Modify the internal logic of <code>updateView</code> API;</li></ul><h2 id="v2-2-0" tabindex="-1">v2.2.0 <a class="header-anchor" href="#v2-2-0" aria-hidden="true">#</a></h2><ul><li>Support SVG elements;</li><li>Optimize internal diff algorithm;</li><li>Add necessary error prompt;</li></ul><h2 id="v2-1-0" tabindex="-1">v2.1.0 <a class="header-anchor" href="#v2-1-0" aria-hidden="true">#</a></h2><ul><li>Fixed the problem that the DOM attribute property could not be assigned;</li><li>Improve the logical problem of converting strings to virtual DOM;</li></ul><h2 id="v2-0-0" tabindex="-1">v2.0.0 <a class="header-anchor" href="#v2-0-0" aria-hidden="true">#</a></h2><ul><li>Inserting data into the head of the list needs to bind the <code>useFkey</code> field to avoid repeated rendering of the <code>DOM</code> node;</li><li>Hide the <code>DOM</code> node event method after rendering;</li><li>Bind the <code>Style</code> style (object);</li><li>The binding properties are uniformly bound using the <code>${}</code> symbol;</li><li>Support HTML template string highlighting (VSCode editor needs to install <code>comment-tagged-templates</code> plugin);</li><li>Support parent and child components to pass values to each other;</li><li>Adapt to Bootstrap5\u3001Tailwindcss UI framework;</li></ul>',30),a=[d];function r(n,c,s,h,p,u){return o(),t("div",null,a)}var m=e(l,[["render",r]]);export{g as __pageData,m as default};
